# ── Données validées disponibles ─────────────────────────────────────────────
df       = st.session_state.df
inputs   = st.session_state.inputs
outputs  = st.session_state.outputs
encodings = st.session_state.encodings

X     = df[inputs].values
Y_all = df[outputs].values


# ═════════════════════════════════════════════════════════════════════════════
