with tab1:
    section_header("📊", "Import & Exploration des données",
                   "Visualisez votre plan d'expérience")
    afficher_import(df, inputs, outputs, encodings=encodings)

    # ── Exports ──────────────────────────────────────────────────────────────
    st.markdown("---")
    st.markdown("#### 📥 Exporter les données")
    _ecol1, _ecol2, _ecol3 = st.columns(3)
